						<u-icon name="arrow-right" color="#e5e5e5"></u-icon>
					</view>
					<!-- <view class="right" v-if="userinfo.mobile" @click="$util.on('/pages/ucenter_sub/bind_mobile?type=3')">
						<text class="desc">{{userinfo.mobile?userinfo.mobile:'去绑定'}}</text>
						<u-icon name="arrow-right" color="#e5e5e5"></u-icon>
					</view> -->
