			</view>
			<!-- <view class="uc-index-item">
				<view class="uc-index-item-right">
					<view class="title">微信</view>
					<view class="right">
						<text class="desc">{{userinfo.weixin_nickname?userinfo.weixin_nickname:'去绑定'}}</text>
						<u-icon name="arrow-right" color="#e5e5e5"></u-icon>
					</view>
				</view>
			</view> -->
			<view class="uc-index-item">
				<view class="uc-index-item-right">
					<view class="title">注册时间</view>
					<view class="right">
						<text
							class="desc">{{userinfo.reg_time?$util.timeFormat(userinfo.reg_time,'yyyy-mm-dd hh:MM:ss'):'无'}}</text>
					</view>
				</view>
			</view>
			<!-- #ifdef MP -->
			<!-- 微信小程序获取短信会有盗刷短信风险 必须隐藏退出登录-->
			<!-- #endif -->
			<!-- #ifndef MP -->
			<view class="uc-index-item" style="margin-top: 30rpx;justify-content:center;">
				<u-button type="" @click="$util.on('/pages/ucenter_sub/set')">安全设置</u-button>
			</view>
			<view class="uc-index-item" style="margin-top: 30rpx;justify-content:center;">
				<u-button type="error" @click="showConfirm=true">退出登录</u-button>
			</view>
			<!-- #endif -->
		</view>
		<loginout-confirm v-model="showConfirm" :list="['退出登录']" @change="handelConfirm" />
	</view>

</template>

<script>
	import md5Libs from "uview-ui/libs/function/md5";
	import config from "common/config.js";
	import {
		mapActions
	} from 'vuex'
	import Confirm from '@/components/confirm'

	export default {
		components: {
			'loginout-confirm': Confirm
		},
		data() {
			return {
				list: [],
				action: '',

				header: {
					authorization: '',
					sign: '',
				},

				showConfirm: false,
			}
		},
		onLoad() {
			this.loadData();
		},
		created() {
			// 监听从裁剪页发布的事件，获得裁剪结果
			uni.$on('uAvatarCropper', path => {



				this.header.authorization = 'Bearer ' + uni.getStorageSync('token');

				this.header.sign = this.$util.reqSign()

				// 可以在此上传到服务端
				uni.uploadFile({
					url: this.action,
					filePath: path,
					name: 'file',
					header: this.header,
					success: (res) => {
						// 判断是否json字符串，将其转为json格式
						let data = this.$u.test.jsonString(res.data) ? JSON.parse(res.data) : res.data;


						if (data.code == 200) {



							//修改头像
							this.$u.api.userinfosave({
									headurl_img: data.data.src,
									type: 'headurl_img',
								})
								.then(res => {
									this.$u.vuex('userinfo.headurl_img', data.data.src);


									this.$util.msg('保存成功')


								}).catch(res => {})


						}

					},
					complete: (res) => {
						// console.log(res);
					}
				});
			})
		},
		methods: {
			...mapActions(['logout']),
			chooseAvatar() {
				// 此为uView的跳转方法，详见"文档-JS"部分，也可以用uni的uni.navigateTo
				// console.log(12);

				uni.chooseImage({
					count: 1, // 默认9
					sizeType: ['compressed'], // 可以指定是原图还是压缩图，默认二者都有
					sourceType: ['album', 'camera'], // 可以指定来源是相册还是相机，默认二者都有
					success: res => {


						this.$u.route({
							// 关于此路径，请见下方"注意事项"
							url: '/uview-ui/components/u-avatar-cropper/u-avatar-cropper',
							// 内部已设置以下默认参数值，可不传这些参数
							params: {
								// 输出图片宽度，高等于宽，单位px
								destWidth: 300,
								// 裁剪框宽度，高等于宽，单位px
								rectWidth: 200,
								// 输出的图片类型，如果'png'类型发现裁剪的图片太大，改成"jpg"即可
								fileType: 'jpg',
								src: res.tempFilePaths[0],
							}
						})
					}
				});

			},
			loadData() {
				this.$u.api.ucenterset({})
					.then(res => {
						this.list = res
					}).catch(res => {})
				this.$u.api.uploadConfig({})
					.then(res => {
						this.action = config.apiurl + '/uni/upload'
					}).catch(res => {})

			},
			async doLogout() {
				await this.$u.api.logout()
				await this.logout()

				uni.redirectTo({
					url: '/pages/user/login'
				})
			},
			handelConfirm(e) {
				const {
					index
				} = e
				if (index === 0) {
					this.doLogout()
				}
			},
		}
	}
</script>

